self.addEventListener("push",t=>{let e=JSON.parse(t?.data?.text()||"{}");t.waitUntil(self.registration.showNotification(e.title||"في السكة",{body:e.body||"لديك إشعار جديد",icon:e.icon||"/icon512_maskable.png",badge:"/icon512_maskable.png",vibrate:[500,250,500,250,500,250,500,250,500],requireInteraction:!0,silent:!1,data:e.data||{}}))}),self.addEventListener("notificationclick",t=>{t.notification.close(),t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(e=>{if(e.length>0){let t=e[0];for(let i=0;i<e.length;i++)e[i].focused&&(t=e[i]);return t.focus()}return self.clients.openWindow(t.notification.data.url||"/driver")}))});